某次学校实验实现的基本排序
数据结构这门课难在麻烦之上，
每次实验都要封装一些数据结构（当时傻，每次还重写又臭又长的宏定义，学生思维太重），
并且要写检查程序（自己写的也是很麻烦（其实没必要）），加之本人上机代码敲的巨慢，
最终数据结构这门课没学到点上
排除个人菜的问题，学校的实验题目太宽泛了（没要学我下面写那么长），像我这种菜鸟写的代码又臃肿又容易出bug
不由感觉提升代码水平全得靠自己疯狂折腾 ~_~
基本的数据封装 ##include &#34;stdio.h&#34; #include &lt;iostream&gt; #include &lt;ctime&gt; #include &lt;cstdlib&gt; #define ERROR 0 #define OK 1 #define Overflow 2 #define Underflow 3 #define NotPresent 4 //元素不存在 #define Duplicate 5 //元素重复存在 #define MaxSize 100001 typedef int KeyType; typedef int Status; typedef int DataType; typedef struct Entry{ KeyType key; DataType data; }entry; typedef struct list{ int n; Entry D[MaxSize]; }List; //输出函数 Status printlist(list*l){ for(int i = 0;i&lt;l-&gt;n;i++){ printf(&#34;%d &#34;,l-&gt;D[i].key); } return OK; } void swap(Entry* a, Entry* b) { Entry temp = *a; *a = *b; *b = temp; } 简单选择排序 #Status choosesort(list* l){ for(int i = 0;i&lt;l-&gt;n-1;i++){ int min = i; for(int j =i+1;j&lt;l-&gt;n;j++){ if(l-&gt;D[min].key&gt;l-&gt;D[j].key) min = j; } swap(&amp;l-&gt;D[i],&amp;l-&gt;D[min]); } return OK; } 直接插入排序 #Status insertsort(list*l){ int i,j; for(i=1;i&lt;l-&gt;n;i++){ Entry temp = l-&gt;D[i]; j=i-1; while(j&gt;=0){ if(l-&gt;D[j].key&gt;temp.key){ l-&gt;D[j+1] = l-&gt;D[j]; l-&gt;D[j] = temp; } j--; } } return OK; } 冒泡排序 #void Bubblesort(list*l){ for(int i = 0;i&lt;l-&gt;n-1;i++) { int start = 0, end = 1; while (end &lt; l-&gt;n) { if (l-&gt;D[start].key &gt; l-&gt;D[end].key) { Entry temp = l-&gt;D[start]; l-&gt;D[start] = l-&gt;D[end]; l-&gt;D[end] = temp; } ++start; ++end; } } } 快速排序 #void QuickSort(List* l, int low, int high) { //快速排序-&gt;递归函数 if (low &lt; high) { //当前待排序序列至少包含2个元素，故low必须&lt;high int i = low; int j = high; Entry min = l-&gt;D[low];//标准位置先设置成low while (i&lt;j){ while (i&lt;j&amp;&amp;l-&gt;D[j].key&gt;min.key){ j--; } if(i&lt;j) l-&gt;D[i++]=l-&gt;D[j]; while(i&lt;j&amp;&amp;l-&gt;D[i].key&lt;min.key){ i++; } if(i&lt;j) l-&gt;D[j--]=l-&gt;D[i]; } l-&gt;D[i] = min; QuickSort(l, low, i - 1);//i前面的递归 QuickSort(l, i + 1, high);//i后面的递归 } } //快排太精妙了 所以学过一段时间就忘 不知道有些人怎么记住那么久的
两路合并排序 #两路合并排序使用了分治法策略
void merge(list*l,int left,int lmid,int rmid,int right){ int i = left,j=rmid;//i,j指向left 和right list temp; int index = 0; while(i&lt;=lmid&amp;&amp;j&lt;=right){ if(l-&gt;D[i].key&lt;=l-&gt;D[j].key){ temp.D[index++]=l-&gt;D[i++]; } else{ temp.D[index++]=l-&gt;D[j++]; } } while(i&lt;=lmid){ temp.D[index++]=l-&gt;D[i++]; } while (j&lt;=right){ temp.D[index++]=l-&gt;D[j++]; } int n=0; for(int k = left;k&lt;=right;k++){ l-&gt;D[k]=temp.D[n++]; } } //这里的处理太傻逼了 还新建了一个链表 但实际怎么做捏 无语 Status mergesort(list*l,int left,int right){ if(left&lt;right){ int mid = left+(right-left)/2; mergesort(l,left,mid); mergesort(l,mid+1,right); merge(l,left,mid,mid+1,right); } return OK; } 堆排序 #void downadjust(list*l,int start,int end){//调整堆 Entry temp = l-&gt;D[start]; for(int i = 2*start+1;i&lt;=end;i*=2){//从start结点的左子结点开始 if(i&lt;end&amp;&amp;l-&gt;D[i].key&gt;l-&gt;D[i+1].key)//如果左子结点小于右子结点 i++;//i指向右子结点 if(temp.key&gt;=l-&gt;D[i].key)//如果父结点大于子结点 break;//调整结束 l-&gt;D[start] = l-&gt;D[i];//否则将子结点值赋给父结点 start = i;//重新赋值开始指针 } l-&gt;D[start] = temp;//调整结束后，将temp值放在最终位置 } Status heapsort(list*l){//堆排序 for(int i = l-&gt;n/2;i&gt;=0;i--){//建堆 downadjust(l,i,l-&gt;n);//调整堆 } return OK; } 测试 #数据封装（随机数） #list* initlist(int n){//在list里生成n个随机数 list *l; l=(list*) malloc(sizeof (list)); l-&gt;n = n; if(n&gt;MaxSize) return nullptr; srand(time(0));//生成随机种子 for(int i = 0;i&lt;n;i++){ l-&gt;D[i].key=(rand()%1000)+1;//随机数赋值 l-&gt;D[i].data = (rand()%50)+1; } return l; } 检查程序 #void deletelist(list*l){ if(!l) return; free(l); } Status testchoosesort(int n){ list *l0 = initlist(n); printf(&#34;

